import{_ as e,o as l,c as t,ai as r}from"./chunks/framework.BQJGzFHV.js";const m=JSON.parse('{"title":"LLM 工具","description":"","frontmatter":{},"headers":[],"relativePath":"suan-api/llm-tools.md","filePath":"suan-api/llm-tools.md"}'),o={name:"suan-api/llm-tools.md"};function n(s,a,i,p,c,d){return l(),t("div",null,[...a[0]||(a[0]=[r('<h1 id="llm-工具" tabindex="-1">LLM 工具 <a class="header-anchor" href="#llm-工具" aria-label="Permalink to “LLM 工具”">​</a></h1><p>LLM 工具是 NJUPT Suan API 为 LLM 提供的可调用 MCP 协议工具。</p><p>MCP 接口端点为 <code>/mcp</code>，支持 streamable HTTP 模式。</p><p>把给 LLM 使用的工具详细介绍给人类看似乎有些不太合适。请放心，Suan API 为工具提供详细的文档和参数注释，LLM 一定看得懂~</p><h2 id="图片说明" tabindex="-1">图片说明 <a class="header-anchor" href="#图片说明" aria-label="Permalink to “图片说明”">​</a></h2><p>课表工具可能会返回课程表图片的 URL。与 API 调用时一样，该 URL 是临时的，计划在 Suan API 的正式版本中设计为固定时间内有效、超时后删除。当前，图片会在 Suan API 重启后清理。</p><p>Suan API 提供一个专门返回图片本身的 LLM 工具，以帮助 LLM 将课程表图片直接包含在对话数据中，避免随着图片超时被删除而丢失。</p><h2 id="工具文档" tabindex="-1">工具文档 <a class="header-anchor" href="#工具文档" aria-label="Permalink to “工具文档”">​</a></h2><p>工具文档也被包含在 WebUI 中。</p>',9)])])}const L=e(o,[["render",n]]);export{m as __pageData,L as default};
